var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"간호사 언니가 내일이면 눈에 감은 붕대를 풀 수 있대.","JPN":"看護師のお姉さんが明日には目に巻いた包帯を外せるって言ってた。","ENG":"The nurse said they'll take off the bandages from my eyes tomorrow.","TWN":"護士姐姐說，明天就能解開眼睛上的繃帶了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 일기장은 간호사 언니가 미리 글씨 연습을 하자고 준 거야.","JPN":"この日記帳は、看護師のお姉さんが文字を書く練習用にくれたの。","ENG":"She gave me this diary so I can practice writing afterwards.","TWN":"這本日記是護士姐姐為了讓我預先練習寫字給我的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하루에 있었던 일 중에 적고 싶은 일을 적으면 된대.","JPN":"一日の出来事の中で書きたいことを書けばいいんだって。","ENG":"She said I can write down whatever happened during the day.","TWN":"她說我可以把一天發生的事情中，想寫的事情寫在這本日記上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 병원에서는 매일매일이 똑같아. 적고 싶은 일이 없어.","JPN":"だけど、病院の中じゃ毎日同じことばかり。書きたいことがない。","ENG":"But every day is the same at the hospital. There's nothing I want to write about here.","TWN":"但在醫院裡，每天的生活都一樣，沒有什麼想寫的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까 내가 쓰고 싶은 얘기를 쓸래.","JPN":"だから私が書きたい話を書くね。","ENG":"So I'm just going to write whatever I want.","TWN":"所以我要把我想到的都寫上去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"간호사 언니가 일기장은 보여 주고 싶은 사람에게만 보여 줘도 된다고 했으니까.","JPN":"看護師のお姉さんが、日記帳は見せたい人にだけ見せてもいいって言ってたから。","ENG":"The nurse said I don't have to show my diary to anyone except those I want.","TWN":"護士姐姐說可以只把日記拿給我想分享的人看。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 있던 창고에는 사람이 많았습니다.","JPN":"私がいた倉庫には大勢の人がいました。","ENG":"There were a lot of people in the warehouse I was in.","TWN":"我所在的倉庫裡有很多人。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔씩 여러 명이 나가고, 여러 명이 들어왔어요.","JPN":"時々何人かの人が出ていって、また何人かが入ってきました。","ENG":"Sometimes several people would go out, and new people would come.","TWN":"偶爾會有很多人出去，很多人進來。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"처음 오는 사람들은 울기도 하고, 비명을 지르기도 하고......","JPN":"初めて来た人は泣いたり、悲鳴を上げたりするけれど……","ENG":"At first, they would cry or scream...","TWN":"第一次來的人有哭的，也有尖叫的……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그러다가 몇 번 어른들에게 불려가면 아무 말도 없이 구석에 앉아 있게 됩니다.","JPN":"そのうち何回か大人たちに呼ばれると、何も言わずに隅っこでうずくまるようになります。","ENG":"But when the grown-ups take them away a few times, they learn to sit quietly in the corner.","TWN":"他們被大人們叫出去幾次，回來後就會縮在角落，一句話也不說。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 그러기 싫어서, 얌전히 지냈어요.","JPN":"私はそうなるのが嫌で、大人しく過ごしました。","ENG":"I stayed quiet because I didn't want that to happen to me.","TWN":"我不想變成那樣，所以一直都乖乖的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"그날까지는요.","JPN":"あの日までは。","ENG":"Until that day, that is.","TWN":"直到那天。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"하아...... 하아...... 하아......","JPN":"はあ……はあ……はあ……","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"哈啊……哈啊……哈啊……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L24_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"잡았다! 이 꼬맹이!","JPN":"捕まえたぞ！　この小娘！","ENG":"I got you! You little punk!","TWN":"抓到了！這小鬼！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"아......?!","JPN":"あ……！？","ENG":"Ah?!","TWN":"啊……？！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"휴우. 앞도 제대로 못 보는 꼬마가 무슨 생각으로 도망친 거야? 귀찮게시리.","JPN":"ふう。ちゃんと前も見えない小娘が何のつもりで逃げたんだ？　面倒くせぇな。","ENG":"Phew... What's a blind kid doing running away? It's such a hassle.","TWN":"呼。路都看不清的小鬼還想逃跑？真麻煩。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"놔......! 이거 놔아......!","JPN":"離して……！　離してよ……！","ENG":"Let go! Let go of me!","TWN":"放……！放開我……！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"허 참, 쓰레기나 주워 먹고 살 걸 입혀 주고 재워 줬더니 은혜를 모르네.","JPN":"ったく、ゴミをあさって生きてるところを面倒見てやったのに、恩知らずだな。","ENG":"You ungrateful little thing. We fed you and gave you a place to sleep when you could've spent your entire life on the street.","TWN":"真是的，給妳這乞丐有吃有穿有住，竟然這麼不知感恩。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"참 신기해. 이 장사 하다 보면 꼭 이렇게 현실파악 못하는 애가 하나씩 섞여 있다니까.","JPN":"不思議だよな。この商売をやっていると、こうやって現実がわからないやつが一人は必ずいるもんだから。","ENG":"It's fascinating, really. Sometimes in this line of business, you always find a kid who just doesn't get how it works.","TWN":"真是不可思議啊。這生意做這麼久了，總會有那麼幾個認不清現實的孩子。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"어허, 장사가 아니라 반정부 활동이지. 누가 들으면 어쩌려고.","JPN":"こら、商売じゃなくて反政府活動だろ。誰かに聞かれたらどうするんだ。","ENG":"Come on now, this isn't business. It's an insurgency. We wouldn't want anyone to get the wrong idea.","TWN":"哦吼，這可不叫生意，叫反政府行動。要是被別人聽到怎麼辦？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"흐윽...... 으......!","JPN":"ふうっ……うっ……！","ENG":"*Sob*... Hngh...","TWN":"嗚嗚……嗚……！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"놔!!","JPN":"離して！？","ENG":"Let go!","TWN":"放開我！！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"아악! 젠장, 이 빌어먹을 꼬마가 내 손을 물어!","JPN":"うあっ！　くそ、この小娘手を嚙みやがった！","ENG":"Ow! This blasted kid is biting my hand!","TWN":"啊啊！該死，這個死小鬼咬我的手！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"아윽......!","JPN":"あうっ……！","ENG":"Arrggh!","TWN":"啊啊……！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L43_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"조심해. 다음에 정부군 놈들과 싸울 때 인간 방패로 써야 한다고.","JPN":"気をつけろよ。今度政府軍と戦う時に、人間の盾として使わなきゃならないんだ。","ENG":"Easy now. We have to use her as a human shield when we fight the government forces next time.","TWN":"小心點。下次和政府軍開打的時候，還得用這小妞當人肉盾牌呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"다리라도 부러져서 걷는 데 지장 생기면 보스가 뭐라고 하겠어?","JPN":"脚でも折って、歩けなくなったらボスに何言われるかわからないぞ？","ENG":"The boss will give you a mouthful if you break her legs or something.","TWN":"如果她腳斷了沒辦法走，你要怎麼跟老闆交代？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"헛소리 말고 잘 붙들고 있기나 해!","JPN":"じゃあちゃんと捕まえとけよ！","ENG":"Shut up and just hold on to her!","TWN":"別扯這些有的沒的，給我好好抓住她！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"이런 것들은 매를 맞아야 정신을 차리지......!","JPN":"こういうやつは痛い目にあわないと言うことを聞かないんだ……！","ENG":"I'm going to beat some sense into the little twerp!","TWN":"這些東西就是得揍一頓才會清醒啊……！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"......바, 방금 들었냐? 여기 침식지대였어?","JPN":"……おい、今の聞いたか？　ここって侵食地帯だったのか？","ENG":"D-did you just hear that? Was this supposed to be a Corrupted Area?","TWN":"……你、你聽到了嗎，剛才的聲音？這裡是侵蝕地區嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"제, 제기랄! 도망쳐야 해! 침식체라도 나오면 끝이라고!","JPN":"く、くそ！　逃げるんだ！　侵食体に出くわしたら終わりだぞ！","ENG":"D-dang it! We have to get out of here! We're dead meat if any C.O.s pop out!","TWN":"該、該死！得快點逃！侵蝕體過來就完蛋了！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"이 애는 어쩌고?!","JPN":"このガキはどうするんだ！？","ENG":"What about the kid?","TWN":"這孩子怎麼辦？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"REVELA_NPC_NULL_NULL","text":{"KOREA":"내버려 둬! 인간 방패로 쓸 고아들은 이 나라에 넘쳐나니까!","JPN":"放っておけ！　盾に使う孤児なんて、この国にいくらでもいる！","ENG":"Leave her here! There's plenty of other orphans in this country to use as human shields!","TWN":"別管了！用來當人肉盾牌的孤兒而已，這國家要多少有多少！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REVELA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REVELB_NPC_NULL_NULL","text":{"KOREA":"가, 같이 가!","JPN":"くそ、行くぞ！","ENG":"W-wait for me!","TWN":"帶、帶上我！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......다리가 안 움직여.","JPN":"……脚が動かない。","ENG":"I can't move my legs...","TWN":"……腿動不了了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"나...... 이대로 죽는 걸까......","JPN":"私……このまま死ぬのかな……","ENG":"Am I... going to die?","TWN":"我……我就要這樣死掉了嗎……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"저기...... 아무라도 좋으니까 들어 줘......","JPN":"誰か……誰でもいいから聞いて……","ENG":"Hello? Is anyone there? Please hear me out...","TWN":"那裡的……是誰都好，請聽我說……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"나...... 소원이 있어......","JPN":"私……お願いがあるの……","ENG":"I... have a wish to make...","TWN":"我……我有個願望……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"다시 태어나면 꼭...... 지금보다 조금만 더 평범하게 살고 싶어...... ","JPN":"今度生まれ変わったら……今よりもう少しだけ平凡に生きたい……","ENG":"If I'm ever born again... I want to have a normal life... ","TWN":"如果能投胎轉世的話……我想過著稍微普通一點的生活……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"평범한 집에서...... 내가 좋아하는 사람들과 평범하게 살 수 있게......","JPN":"平凡な家で……私が好きな人たちと平凡に暮らせるように……","ENG":"In a normal home... Living alongside people I like...","TWN":"在普通的家裡……和我喜歡的人一起過著平凡的生活……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_QM","text":{"KOREA":"그건 곤란한걸.","JPN":"それは困ったな。","ENG":"Well, that's going to be tricky.","TWN":"那應該有點難。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_QM","text":{"KOREA":"네가 다시 태어나기 전까지는 시간이 아주 많이 남아 있거든.","JPN":"君が生まれ変わるまでは、時間がまだたくさん残っているんだよ。","ENG":"Because you still got many years ahead of you until your next chance at life.","TWN":"因為妳離投胎還早得很呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_QM","text":{"KOREA":"하지만 지금이라도 괜찮다면 내가 조금은 도와 줄 수 있을 것 같은데.","JPN":"今からでもよければ、私が少しは力になってあげられそうだが。","ENG":"But I think I could help you out a little, if you don't mind.","TWN":"但如果妳不介意是現在的話，我倒是能幫妳一點小忙。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"누...... 누구......?","JPN":"だ……誰……？","ENG":"Who... Who are you?","TWN":"誰……是誰……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_QM","text":{"KOREA":"관리자...... 아니, 선생님이라고 부르렴.","JPN":"管理者……いや、先生と呼んでくれればいい。","ENG":"I'm the Administrator... Never mind, just call me Teacher.","TWN":"管理者……不，叫我老師吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"지금은 그게 더 어울릴 것 같으니까.","JPN":"今はそのほうが似合いそうだからね。","ENG":"I think that's probably more appropriate right now.","TWN":"因為現在這個稱呼似乎更合適我。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"가, 가까운 데에 침식체가 있어...... 어서 도망쳐......","JPN":"ち、近くに侵食体がいるの……早く逃げて……","ENG":"There's a C.O. nearby... Get out of here...","TWN":"附、附近有侵蝕體……快點逃……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"내 생각을 해 주는 거니? 착한 아이구나.","JPN":"私のことを心配してくれてるのか？　優しい子だね。","ENG":"Are you worried about me? Well, aren't you a nice kid.","TWN":"妳在擔心我嗎？真是個善良的孩子啊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 걱정하지 않아도 된단다.","JPN":"でも、何も心配することないよ。","ENG":"But you don’t need to worry about me.","TWN":"但是，妳並不用擔心。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"선생님에겐 재미있는 물건이 많거든.","JPN":"先生には面白い物がたくさんあるから。","ENG":"I've got lots of interesting gadgets, you see.","TWN":"因為老師有很多有趣的東西呢。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그중에는 침식체들이 우릴 볼 수 없게 만드는 물건도 있지.","JPN":"その中には、侵食体が私たちを見れないようにする物もある。","ENG":"Including something that can make us invisible to the C.O.s.","TWN":"其中也有能讓侵蝕體看不到我們的東西。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"저, 정말......?","JPN":"ほ、本当に……？","ENG":"R-really?","TWN":"真、真的嗎……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래. 잠시만 조용히 하고 있으면 저 녀석들은 그냥 지나가 버릴 거란다.","JPN":"ああ。しばらくじっとしていたら、あいつらは素通りしていくはずだよ。","ENG":"That's right. If you stay quiet for a little bit, they'll just pass us by.","TWN":"沒錯。只要妳能安靜一下下，它們馬上就會走掉。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그, 그래도......","JPN":"で、でも……","ENG":"B-but still...","TWN":"可、可是……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"불안하면 손을 잡아 줄게.","JPN":"不安なら手を握ってあげよう。","ENG":"If you're nervous, I'll hold your hand.","TWN":"害怕的話就抓住我的手。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"자, 무서워하지 않아도 돼. 선생님도 네 옆에 계속 있을 거란다.","JPN":"ほら、怖がることはない。先生は君のそばにずっといるからね。","ENG":"There, there. You don't have to be afraid anymore. I'll stay by your side.","TWN":"來，不用擔心。老師會一直在妳身邊的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그, 그럼...... 나...... 정말 살 수 있는 거야?","JPN":"じゃ、じゃあ……私……本当に生きられるの？","ENG":"Y-you mean... I... don't have to die now?","TWN":"那、那麼……我……我真的能活下去了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"물론이지.","JPN":"もちろんだ。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"흑...... 흐윽......","JPN":"ぐすん……ぐす……","ENG":"*Sob* *Sniffle*","TWN":"嗚……嗚嗚..."},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"자, 자. 그동안 많이 힘들었지?","JPN":"君、今まで大変だっただろ？","ENG":"There, there. It's been rough, eh?","TWN":"來吧，這段時間妳過得很辛苦吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"이젠 안전하니까 마음 편히 쉬렴.","JPN":"もう安全だから、ゆっくり休めばいい。","ENG":"You're safe now. Relax.","TWN":"現在妳已經安全了，放心吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님은 모르는 게 없는 신기한 사람이었어요.","JPN":"先生は何でも知っている不思議な人でした。","ENG":"The Teacher seemed to know everything about the world,","TWN":"老師可是個無所不知、很不可思議的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 궁금한 게 생기면 뭐든 알려 주셨죠.","JPN":"私が知りたいことは何でも教えてくれたんです。","ENG":"and taught me anything I was curious about.","TWN":"如果我有什麼好奇的事，老師都會告訴我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"자기 자신에 대한 것만 쏙 빼고요.","JPN":"自分自身のことだけを除いて。","ENG":"Except any details about Teacher.","TWN":"除了關於我的事情以外。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"자, 여기.","JPN":"ほら、これだ。","ENG":"Here you go.","TWN":"來，這裡。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"오, 잘 익혔구나. 솜씨가 좋은걸.","JPN":"おお、いい焼き加減だ。器用なんだね。","ENG":"Oh, that's perfect. You're pretty good at this.","TWN":"哦，做得很好啊，手藝不錯。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"혹시 요리 배운 적 있니?","JPN":"ひょっとして料理を習ったことがあるのか？","ENG":"Have you ever learned to cook?","TWN":"妳該不會有學過料理嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"아니. 오늘이 처음이야.","JPN":"ううん。今日が初めて。","ENG":"No. This is the first time.","TWN":"沒有，我今天是第一次做。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"손은 괜찮아? 아까 시범 보여 주려다 데일 뻔했잖아.","JPN":"手は大丈夫？　さっきお手本を見せようとして、やけどするところだったでしょ。","ENG":"How's your hand? You almost burned yourself trying to show me how to start a fire.","TWN":"您的手沒事吧？剛才是不是為了示範給我看差點燙傷了？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하, 이론은 잘 알아도 실제로 하는 건 좀 어려워서 말이야.","JPN":"ははっ、頭ではわかっていても実際やるのは難しくてね。","ENG":"Hah hah, I knew the theory behind it, but it's a lot harder than it looks.","TWN":"哈哈，就算知道理論，實際做起來卻有點難呢。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그런데 선생님은 이 나라에 왜 왔어?","JPN":"ところで、先生はどうしてこの国に来たの？","ENG":"So what are you doing in this country?","TWN":"不過老師為什麼會來這個國家？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"흐음...... 내가 가진 특별한 컴퓨터에 필요한 부품이 여기 있다고 해서......","JPN":"ふむ……私の特別なコンピューターに必要な部品がここにあると聞いて……","ENG":"Hmm... I was told the component required for my very special computer would be here...","TWN":"嗯……因為我有個很特別的電腦，它需要的一個零件在這個國家……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"아니, 그냥 보물이 있다는 말을 듣고 찾으러 왔단다.","JPN":"いや、ただ宝物があるという話を聞いて探しにきたんだ。","ENG":"I mean, they just said there's a treasure here. So I came looking for it.","TWN":"不，妳就當我是來找寶藏的好了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그럼 보물은 찾았어? 혹시 날 구하느라 잃어 버렸다거나......","JPN":"それで、宝物は見つかった？　まさか私を助けようとして失くしたとか……","ENG":"Did you find the treasure? Or did you lose it because you had to save me?","TWN":"那您找到寶藏了嗎？會不會因為救我所以沒有……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하. 아쉽게도 헛소문이었던 것 같아.","JPN":"はは。残念ながらただの噂だったみたいだ。","ENG":"Hah hah. Unfortunately, I guess I was just chasing a rumor.","TWN":"哈哈。很遺憾，寶藏好像是個謠言。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래도 이렇게 똑똑한 학생이 생겼으니 다른 보물을 찾았다고 해야겠지.","JPN":"でもこんなに賢い生徒と会えたのだから、別の宝物を見つけたと言うべきだろうな。","ENG":"Still, I guess I found a treasure after all. You're one smart kid.","TWN":"但能得到一個這麼聰明的學生，也算是找到了另一種寶藏呢。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......그럼, 머리 쓰다듬어 줘.","JPN":"……それじゃあ、頭をなでて。","ENG":"Then pat me on my head.","TWN":"……那就，摸摸我的頭。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"응? 머리?","JPN":"うん？　頭を？","ENG":"Hm? Your head?","TWN":"嗯？頭？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"사람들은 보물이 생기면 소중하게 쓰다듬잖아.","JPN":"人は宝物ができると大事になでるでしょう？","ENG":"People like to pat their precious treasures.","TWN":"人們獲得寶物時，不是會很珍惜地撫摸它們嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"나도 보물이니까, 쓰다듬어 줘.","JPN":"私も宝物だから、なでてちょうだい。","ENG":"Since I'm your treasure, pat me.","TWN":"因為我也是寶物，所以請摸摸我的頭。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......그, 그래. 그렇구나.","JPN":"……ああ、そうか。そうだな。","ENG":"O-okay. I see.","TWN":"……是，是嗎。是這樣啊。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님은 약한 사람이었습니다.","JPN":"先生は弱い人でした。","ENG":"The Teacher wasn't very strong,","TWN":"老師是個體力非常弱的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"나보다 오래 못 달리고, 햇빛을 쬐면 금방 어지러워했어요.","JPN":"私よりも長く走れず、日に当たるとすぐにめまいを起こしました。","ENG":"unable to run as long as I could, getting dizzy under the sun.","TWN":"不但跑得沒我久，一曬到太陽還會馬上暈過去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 선생님께 배웠어요.","JPN":"でも、先生から学んだんです。","ENG":"But I learned a lot from Teacher.","TWN":"但是我從老師那裡學到了一件事……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"나도 다른 사람에게 도움이 될 수 있다는 걸.","JPN":"私も他の人の役に立てるということを。","ENG":"I learned that I could help someone else too.","TWN":"那就是我也有能力幫助別人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님, 또 넘어질 뻔했어.","JPN":"先生、また倒れるところだったよ。","ENG":"You almost tripped again, Teacher.","TWN":"老師，您又差點摔倒了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하, 이거 면목이 없구나. 나도 몸이 튼튼한 편은 아니라서.","JPN":"はは、申し訳ない。私も体が丈夫なほうではなくてね。","ENG":"Hah hah. This is embarrassing. I'm not very fit either.","TWN":"哈哈，真丟臉啊，畢竟我的身體沒有很強壯。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"내, 내가 부축해 줄게. 이쪽으로 기대.","JPN":"わ、私が支えてあげる。こっちに寄りかかって。","ENG":"L-let me help you walk. Lean on me.","TWN":"我、我來扶著您，您靠在這裡。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래도 어른 체면이 있지. 아이에게 기대면 쓰나.","JPN":"いや、大人としてそれは無理だ。子供に頼るなんてできない。","ENG":"Hey, but I'm a responsible adult. I shouldn't have to rely on a child.","TWN":"我也有身為大人的面子啊，怎麼能靠著一個孩子呢？"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"괜찮아. 선생님이 아니었으면...... 난 그때 죽었을 거야.","JPN":"大丈夫。先生がいなかったら……私はあの時死んでいたはずだから。","ENG":"It’s okay. If it weren't for you... I'd be dead already.","TWN":"沒關係。如果不是老師救了我……我早就死了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"도움을 받으면 갚아야 한다고 했잖아. 난 선생님이 가르쳐 준 대로 할래.","JPN":"助けてもらった恩は返さなきゃいけないって言ったでしょ。私は先生が教えてくれたとおりにする。","ENG":"You said I should pay people who help me back. I'll do as you taught me.","TWN":"老師不是教過我要知恩圖報嗎？我會按照老師教的去做。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그러니까...... 이 정도는 아무것도 아니야.","JPN":"だから……これくらいどうってことない。","ENG":"So... This is nothing compared to what you've done for me.","TWN":"而且……這點小事也不算什麼。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래, 고맙구나. 그럼 조금만 기댈게.","JPN":"そうか、ありがとう。なら少しだけ甘えるよ。","ENG":"I see... Thank you. Then I guess I'll lean on you just a little.","TWN":"是嗎，謝謝妳。那就讓我靠一會吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"힘들고, 위험할 때도 있었지만 늘 기뻤습니다.","JPN":"大変で危険な時もありましたが、いつも幸せでした。","ENG":"Things got tough and even dangerous at times, but I was always happy.","TWN":"雖然也有很辛苦、很危險的時候，但我過得很開心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님과 함께였으니까.","JPN":"先生と一緒だったから。","ENG":"Because I was with my Teacher.","TWN":"因為我跟老師在一起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"내일이면 국경을 넘을 수 있을 거야.","JPN":"明日には国境を超えられるはずだ。","ENG":"We should be able to cross the border tomorrow.","TWN":"明天就能越過國境了吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그러니 오늘은 일찍 자서 체력을 비축해 두렴.","JPN":"だから今日は早めに寝て体力を蓄えておきなさい。","ENG":"So try to get plenty of sleep today and save up your energy.","TWN":"今天早點睡，多保存點體力吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님은 대단한 사람 같아.","JPN":"先生はすごい人だと思う。","ENG":"You're amazing.","TWN":"我覺得老師是個很厲害的人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래? 내가......?","JPN":"そうか？　私が……？","ENG":"Really? I am?","TWN":"嗯？我嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"응. 모르는 것도 없고, 요리하는 법도 가르쳐 주고, 죽을 뻔했을 때도 구해 주고, 그리고...... 그리고 또......","JPN":"うん。何でも知ってるし、料理も教えてくれるし、死にそうなところを助けてくれたし、あと……それから……","ENG":"Yeah. You know everything. You even taught me how to cook, and saved my life. And... and...","TWN":"嗯。老師沒有不知道的事情，不但教我做料理，還在我快死掉的時候救了我，而且……還有……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"꼭 그렇지는 않아.","JPN":"別にそうでもないよ。","ENG":"That's not entirely true.","TWN":"並不全然是這樣。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"같이 다니면서 봤지? 선생님은 서툰 점이 많은 사람이야.","JPN":"一緒に過ごす間に見ただろ？　先生は不器用な人なんだ。","ENG":"Haven't you seen what I'm like? I can be very clumsy too.","TWN":"妳也看到了吧？老師是個有很多缺點的人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래서 실패도...... 아주 많이 겪었지.","JPN":"だから失敗も……たくさん経験したよ。","ENG":"So I've seen... plenty of failure as well.","TWN":"還有過……很多次失敗的經歷。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"실패......","JPN":"失敗……","ENG":"Failure...","TWN":"失敗……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"하, 하지만 포기 안 했지? 선생님은 끈기 있는 사람이잖아?","JPN":"で、でも諦めなかったでしょ？　先生は粘り強い人だよね？","ENG":"B-but you never gave up, have you? You're a tenacious person, right?","TWN":"但、但是老師沒有放棄吧？老師是個非常堅強的人吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"......그럼. 당연하지.","JPN":"……ああ、もちろんだ。","ENG":"Right... Of course I am.","TWN":"……那是，當然的啦。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"선생님은 포기하지 않는단다.","JPN":"先生は諦めないよ。","ENG":"I'll never give up.","TWN":"老師是不會放棄的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"선생님의...... 소원을 이룰 때까지.","JPN":"先生の……願いを叶えるまでは。","ENG":"Until... my wish comes true.","TWN":"直到老師的……願望實現為止。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"소원? 선생님도 소원이 있어?","JPN":"願い？　先生にも願いがあるの？","ENG":"Your wish? You've got a wish too?","TWN":"願望？老師也有願望嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그럼, 나도 소원이 있지.","JPN":"ああ、私にも願いがある。","ENG":"Sure, I've got a wish.","TWN":"是啊，老師當然會有願望。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그게 뭔데?","JPN":"それって何？","ENG":"What is it?","TWN":"是什麼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"음, 그건...... <color=#ffd34c>우주 평화</color>?","JPN":"うむ、それは……<color=#ffd34c>宇宙の平和</color>？","ENG":"Um... Well... <color=#ffd34c>Universal peace</color>?","TWN":"呃，是……<color=#ffd34c>宇宙和平</color>?"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"풋......!","JPN":"ぷっ……！","ENG":"Pfft!","TWN":"噗……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"뭐야, 그게. 바보 같아.","JPN":"何それ。バカみたい。","ENG":"Seriously? That sounds silly.","TWN":"那是什麼啊，像個笨蛋一樣。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하하, 역시 그런가?","JPN":"はは、やはりそうか！","ENG":"Hah hah, does it?","TWN":"哈哈，果然是那樣嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 네 웃는 모습을 처음 봐서 그런지 부끄럽진 않구나.","JPN":"でも君の笑顔を初めて見たからか、そこまで恥ずかしくはないな。","ENG":"But I'm not so embarrassed since I made you smile.","TWN":"不過，不知道是不是因為第一次看到妳的笑容，老師沒有覺得不好意思呢。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"잘 어울리는걸.","JPN":"よく似合うじゃないか。","ENG":"It looks good on you.","TWN":"很適合妳喔。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......나, 웃은 적 없어?","JPN":"……私、笑ったことないの？","ENG":"I... never smiled?","TWN":"……我，沒有笑過嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"모르고 있었구나. 실은 조금 섭섭했단다.","JPN":"知らなかったんだね。実は少し寂しかったよ。","ENG":"Oh, so you didn't know. Actually, I've been a bit disappointed.","TWN":"原來妳都不知道啊，事實上還有點寂寞的樣子呢。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"모...... 몰랐어. 선생님 앞에선 매일 웃고 있는 줄 알았는데.","JPN":"し……知らなかった。先生の前ではいつも笑ってるんだと思ってたのに。","ENG":"I... I had no idea. I thought I'd be smiling in front of you all day.","TWN":"我……我不知道，我以為自己每天都是帶著笑容面對老師的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그럼 앞으로는 계속 웃고 다닐래. 자.","JPN":"じゃあこれからはずっと笑顔でいるね。ほら。","ENG":"Okay, then. I'll keep smiling from now on. See?","TWN":"那我以後要一直笑下去，像這樣。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그렇다고 손가락으로 당겨서까지 억지로 웃을 필요는 없단다.","JPN":"だからって、指で引っ張ってまで無理やり笑顔を作る必要はない。","ENG":"You don't have to pull your mouth back and force a smile like that.","TWN":"話是這麼說，也沒必要用手指拉著嘴角，勉強自己笑出來。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"언젠가는 그러지 않아도 자연스럽게 웃을 수 있을 거야.","JPN":"いつかはそうしなくても、自然と笑える日がくるだろう。","ENG":"I'm sure you'll learn to smile naturally one day.","TWN":"總有一天，妳也能自然地笑出來的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님, 나도 소원이 생겼어.","JPN":"先生、私にも願い事ができた。","ENG":"I've got a wish too, Teacher.","TWN":"老師，我也有願望了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"알고 있단다. 다음에 태어나면 평범한 삶을 살고 싶다고 했었나?","JPN":"知ってる。今度生まれ変わったら、平凡な人生を送りたいと言ってたっけ？","ENG":"I'm aware. You said you wanted to live an ordinary life next time, right?","TWN":"我知道啊。妳說妳投胎轉世的話，想過平凡的生活吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"그, 그거 말고. 이번엔 다른 소원이야.","JPN":"そ、そうじゃなくて。今回は違うの。","ENG":"N-not that. A different wish.","TWN":"不，不是那個，這次是別的願望。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그래? 그럼 새로운 소원은 뭔데?","JPN":"そうか？　じゃあ、新しい願いは何だい？","ENG":"Yeah? What is this new wish then?","TWN":"是嗎？那妳新的願望是什麼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"서, 선생님은 똑똑한데 몸도 약하고 실수도 많이 하니까......","JPN":"せ、先生は賢いけど体も弱くて、失敗もたくさんするから……","ENG":"Y-you're smart, but you're clumsy and weak...","TWN":"老、老師雖然很聰明，但是身體不太好，也經常失誤……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님이 소원을 이룰 때까지......","JPN":"先生が願いを叶えるまでは……","ENG":"So until your wish comes true, I...","TWN":"所以直到老師的願望實現的那天……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"손을 잡고 싶어요. 선생님.","JPN":"手を握っていたいんです。先生。","ENG":"I want to hold your hand. Teacher.","TWN":"我想一直牽著您的手，老師。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"예전처럼, 선생님과 함께할 수 있게.","JPN":"昔みたいに、先生と一緒にいられるように。","ENG":"I want to be with you again, like before.","TWN":"像之前那樣，跟老師在一起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"그로니아에서 샤레이드까지 걸어오셨다고요?","JPN":"グロニアからシャレードまで歩いて来たんですか？","ENG":"You walked all the way from Gronia to Charade?","TWN":"你說你是從葛羅尼亞走到了查雷德？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 건강해 보이시지는 않는데...... 정말 고생하셨습니다.","JPN":"そこまで丈夫な方には見えませんが……本当にご苦労様でした。","ENG":"You don't strike me as someone that fit... That must have been real tough.","TWN":"雖然你的健康狀況不像能走那麼遠的樣子……但真是辛苦你了。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"동행한 아이에 대해서는 일단 임시 의료 지원이 이루어질 거예요.","JPN":"お連れの子供には、ひとまず臨時の医療支援が行われる予定です。","ENG":"As for the child accompanying you, we'll provide her with some initial medical care for now.","TWN":"我們會先對同行的孩子進行臨時的醫療支援。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 의료진들 얘기로는...... 시력이 완전히 회복될지는 장담하기 어렵다더군요.","JPN":"しかし医師たちの話によると……視力が完全に回復するかは断言できないそうです。","ENG":"But according to the medical staff, they can't guarantee when her sight would be restored.","TWN":"然而根據醫療團隊的說法……無法保證她的視力能夠完全恢復。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"강한 아이입니다. 반드시 나을 수 있을 거에요.","JPN":"強い子です。きっと治るはずです。","ENG":"She's a strong girl. I'm sure she'll recover.","TWN":"她是個堅強的孩子，一定都會好起來的。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 임시 의료 지원은 기간이 짧아요.","JPN":"ですが、臨時の医療支援は期間が長くありません。","ENG":"But this temporary medical care won't last long.","TWN":"不過臨時醫療支援的時間很短。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"정식으로 장기적인 치료를 받으려면 관리국의 망명 허가가 필요합니다.","JPN":"正式に長期的な治療を受けるためには、管理局の亡命許可が必要です。","ENG":"In order to receive regular treatment, she'll need authorization from the Administration to be granted asylum.","TWN":"想要得到長期治療，必須要有管理局的難民許可。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"아시겠지만 샤레이드가 관리국 직할 도시로 선포된 지 얼마 안 되서...... 허가 나기가 쉽지 않아요.","JPN":"ご存じだと思いますが、シャレードは管理局直轄都市になったばかりで……許可を取るのは難しいんです。","ENG":"As you know, Charade was just recently declared to be under the Administration's direct control... So the approval might not come so easily.","TWN":"如你所知，查雷德才剛宣布成為管理局的直轄城市……要獲得許可非常不容易。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"허가라면 걱정 마세요. 나올 테니까요.","JPN":"許可のことなら心配ありません。必ず下りるでしょうから。","ENG":"Don't worry about that. It'll be approved.","TWN":"不用擔心許可的事，它會下來的。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 여기 상황을 잘 모르시는 것 같은데......","JPN":"いや、ここの状況をご存知ないようですが……","ENG":"Wait, I don't think you understand the situation here...","TWN":"不，你似乎對這裡的情況不太瞭解……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"잠시만요. 전화 좀 받고요.","JPN":"待ってください。電話に出ますので。","ENG":"Oh, one moment please. I have to take this phone call.","TWN":"等等，我接下電話。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"네, 난민구호소 담당입니다.","JPN":"はい、難民救護所の担当の者です。","ENG":"Yes, this is the Refugee Camp.","TWN":"是的，我是難民救助所負責人。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"......네? 저, 정말요? 무조건 승인하라고요?","JPN":"……え？　ほ、本当ですか？　条件を問わず承認ですか？","ENG":"What? R-really? Approve it no matter what?","TWN":"……咦？真，真的嗎？無條件批准？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"아, 알겠습니다.","JPN":"わ、わかりました。","ENG":"U-understood.","TWN":"是，我明白了。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OFFICER_ADMIN_NULL_NULL","text":{"KOREA":"이봐요, 당신. 대체 무슨 마법을 쓴 거죠?","JPN":"いや、あなた。いったいどんな魔法を使ったんですか？","ENG":"Hey, you... What kind of magic did you just pull off?","TWN":"我說你……到底是用了什麼魔法？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NURSE_NPC_NULL_NULL","text":{"KOREA":"앗, 얘! 안 돼! 그리로 가면......!","JPN":"あっ、ちょっと！　ダメよ！　そこに行っちゃ……！","ENG":"Hey, kid! No! You can't go there!","TWN":"啊，這孩子！不可以！去那邊的話……！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING"},{"id":"L26_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님......! 선생님!","JPN":"先生……！　先生！","ENG":"Teacher! Teacher!","TWN":"老師……！老師！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님, 어디 있어? 거기 있는 거 맞지? 나 보고 있지?","JPN":"先生、どこにいるの？　そこにいるんでしょ？　私を見てるよね？","ENG":"Where are you, Teacher? You're there, right? You're watching me, aren't you?","TWN":"老師，您在哪？您在那邊吧？您在看我吧？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"나, 앞으로 많이 웃을게. 그러니까 가지 마.","JPN":"私、これからたくさん笑う。だから行かないで。","ENG":"I'm going to keep smiling from now on. So please don't leave me.","TWN":"我以後會常常笑的，所以不要走。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"나...... 나 앞으로도 선생님이랑 같이 있을래......","JPN":"私……これからも先生と一緒にいたい……","ENG":"I... I want to stay by your side...","TWN":"我……我以後也想和老師在一起……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생...... 님......","JPN":"先……生……","ENG":"Teacher... Teacher...","TWN":"老……老師……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NURSE_NPC_NULL_NULL","text":{"KOREA":"후우, 같이 오신 분이라면 벌써 떠나셨단다.","JPN":"ふう、一緒に来た方ならもうここを去ったわよ。","ENG":"Phew... The person who brought you here already left.","TWN":"唉，如果妳在找和妳一起來的人，他已經走掉了。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"거짓말......!","JPN":"嘘……！","ENG":"You're lying!","TWN":"騙人……!"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NURSE_NPC_NULL_NULL","text":{"KOREA":"거짓말이 아니야. 자, 너한테 읽어 주라고 하셨던 쪽지란다.","JPN":"嘘じゃないわ。ほら、あなたに読ませてほしいと渡された手紙なの。","ENG":"I'm not lying. Here. This Teacher of yours asked me to read you this note.","TWN":"我沒有騙人。來，這是他留給妳的訊息。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"쪽지......?","JPN":"手紙……？","ENG":"A note?","TWN":"訊息……？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"말도 없이 떠나서 미안하구나.","JPN":"何も言わずに立ち去ってすまないね。","ENG":"I'm sorry I left without saying anything.","TWN":"對不起，我一句話也沒說就離開了。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 내가 하는 일은 아주 위험한 것들이고, 또 무서운 적들도 많이 있단다.","JPN":"でも私の仕事はとても危険なことばかりで、恐ろしい敵もたくさんいる。","ENG":"But I'm involved in a very dangerous line of work. I also have many formidable foes.","TWN":"但我的工作非常危險，還有很多很可怕的敵人。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"나와 관계되어서 널 위험에 처하게 하고 싶지는 않아.","JPN":"私と関わらせて、君を危険な目に遭わせたくはないんだ。","ENG":"I wouldn't want to put you in harm's way because of me.","TWN":"我不想因為我的關係，害妳身陷在危險之中。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"위, 위험 같은 거 상관없단 말이야......!","JPN":"き、危険なんてどうだっていいのに……！","ENG":"I-I don't care how dangerous it is!","TWN":"我、我才不在乎什麼危險……！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"싫어...... 나, 나 방해 안 할 건데...... 나도 도와 줄 수 있는데......","JPN":"嫌よ……わ、私邪魔しないから……私も手伝えるのに……","ENG":"No... I-I can stay out of your way... I can help you too...","TWN":"不要……我、我不會妨礙您的……我能幫上您的忙……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"말했듯이 나는 아주 많은 실패를 겪었단다. 그리고 그만큼 구하지 못한 사람들도 많아.","JPN":"前にも言ったが、私はたくさんの失敗を経験してきた。その数だけ救えなかった人も多い。","ENG":"Like I said, I've been through lots of failure. I also failed to save many lives in the process.","TWN":"就像我說過的，我經歷了很多次的失敗，還有很多沒能拯救的人們。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"하지만 이번에는 너를 구하는 데 성공했어.","JPN":"でも今回は君を救うことができた。","ENG":"But this time, I managed to save you.","TWN":"不過這次我成功救了妳。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그러니까 내가 그 사실을 자랑스럽게 여길 수 있게......","JPN":"だから、私がその事実を誇らしく思えるように……","ENG":"So let me take some pride in this one victory...","TWN":"所以，為了能讓我對這件事感到驕傲……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"앞으로도, 웃으면서 지내 주렴.","JPN":"これからも、笑顔で過ごしてほしい。","ENG":"Always stay smiling.","TWN":"之後也，笑著活下去吧。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"흑...... 흐윽......","JPN":"ぐすん……ぐす……","ENG":"*Sob*... *Sniffle*...","TWN":"嗚……嗚嗚……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"......알았어. 나 웃으면서 지낼게.","JPN":"……わかった。私、笑顔で生きるよ。","ENG":"Okay... I'll keep smiling.","TWN":"……我知道了，我會帶著笑容活下去的。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"웃는 거...... 잘 못하지만......","JPN":"笑うのは……上手じゃないけど……","ENG":"Although... I'm not very good at it...","TWN":"雖然我……不太擅長笑……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"선생님이랑 언제 다시 만나더라도......","JPN":"いつか先生とまた再会しても……","ENG":"I'll keep practicing so that if I ever meet you again...","TWN":"但為了未來能再次見到老師……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_CHILD_NULL_NULL","text":{"KOREA":"예쁘게 웃을 수 있게.","JPN":"明るく笑えるように。","ENG":"I can smile beautifully for you.","TWN":"我會努力笑的。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_CHILD_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 만나고 싶어요.","JPN":"また会いたいですね。","ENG":"I want to meet you again.","TWN":"好想再見到您。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님.","JPN":"先生。","ENG":"Teacher.","TWN":"老師。"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};